import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import LandingPage from './pages/LandingPage';
import SignupLogin from './pages/SignupLogin';
import Dashboard from './pages/Dashboard';
import TravelStories from './pages/TravelStories';
import VerifiedStays from './pages/VerifiedStays';
import Settings from './pages/Settings';

const Routes = () => {
    return (
        <Router>
            <Switch>
                <Route path="/" exact component={LandingPage} />
                <Route path="/signup-login" component={SignupLogin} />
                <Route path="/dashboard" component={Dashboard} />
                <Route path="/travel-stories" component={TravelStories} />
                <Route path="/verified-stays" component={VerifiedStays} />
                <Route path="/settings" component={Settings} />
            </Switch>
        </Router>
    );
};

export default Routes;
